<template>
  <div class="dash-page">
    <div class="dash-head">
      <div><h1>{{ dashboard?.name ?? 'Dashboard' }}</h1><p v-if="companyId" class="dash-context">Showing the selected company</p></div>
      <div class="dash-actions">
        <button v-if="hasRole('admin')" class="btn btn-ghost btn-sm" @click="showSettings = true">Manage</button>
        <button v-if="hasRole('admin')" class="btn btn-primary btn-sm" @click="editing = !editing">{{ editing ? 'Done editing' : 'Edit layout' }}</button>
      </div>
    </div>
    <div v-if="error" class="error-banner">{{ error }}</div>
    <div v-else-if="!dashboard" class="dash-loading">Loading dashboard…</div>

    <div v-else class="dash-grid" :class="{ editing }" @dragover.prevent @drop="dropOnCanvas">
      <article v-for="widget in dashboard.widgets" :key="widget.id" class="dash-widget"
        :class="{ dragging: draggingId === widget.id, 'widget-chart': !['device_summary', 'recent_alerts'].includes(widget.type) }" :style="widgetStyle(widget)"
        :draggable="editing" @dragstart="startDrag(widget.id)" @dragend="draggingId = null" @dragover.prevent @drop.stop="dropOnWidget(widget)">
        <div v-if="editing" class="widget-editbar"><span class="drag-handle">⋮⋮ Drag</span><span class="widget-edit-actions">
          <button title="Narrower" @click.stop="resize(widget, -1)">−</button><button title="Wider" @click.stop="resize(widget, 1)">+</button>
          <button title="Remove widget" @click.stop="removeWidget(widget.id)">×</button>
        </span></div>
        <div v-if="widget.type === 'device_summary'" class="stat-grid dash-stats">
          <div class="stat-card c-blue"><div class="stat-label">Total Devices</div><div class="stat-value">{{ data?.summary.total ?? '—' }}</div><div class="stat-sub">{{ data?.summary.approved ?? 0 }} approved</div></div>
          <div class="stat-card c-teal"><div class="stat-label">Online Now</div><div class="stat-value">{{ data?.summary.online ?? '—' }}</div><div class="stat-sub">checked in &lt; 5 min ago</div></div>
          <div class="stat-card c-amber"><div class="stat-label">Pending Approval</div><div class="stat-value">{{ data?.summary.pending ?? '—' }}</div><RouterLink class="stat-sub" to="/devices">Review →</RouterLink></div>
          <div class="stat-card c-red"><div class="stat-label">Active Alerts</div><div class="stat-value">{{ activeAlerts.length }}</div><div class="stat-sub">{{ alertBreakdown }}</div></div>
        </div>
        <template v-else-if="widget.type === 'recent_alerts'">
          <div class="widget-title">{{ widget.title || 'Recent Alerts' }} <RouterLink to="/global/alerts">View all →</RouterLink></div>
          <div class="widget-table-wrap"><table class="widget-table"><thead><tr><th>Created</th><th>Priority</th><th>Category</th><th>Message</th><th>Company</th><th>Hostname</th></tr></thead>
            <tbody><tr v-for="alert in recentAlerts" :key="alert.id" @click="router.push('/global/alerts/' + alert.id)"><td class="mono">{{ formatDate(alert.alerted_at) }}</td><td><span class="pri-badge" :class="`pri-${alert.priority}`">{{ alert.priority }}</span></td><td>{{ categoryLabel(alert.check_type) }}</td><td>{{ alertMessage(alert) }}</td><td>{{ alert.tenant_name }}</td><td><RouterLink :to="'/devices/' + alert.device_id" @click.stop>{{ alert.hostname ?? '—' }}</RouterLink></td></tr>
              <tr v-if="!recentAlerts.length"><td colspan="6" class="empty-cell">No recent alerts</td></tr></tbody></table></div>
        </template>
        <template v-else>
          <div class="widget-title">{{ widget.title || widgetLabels[widget.type] }}</div>
          <DonutChart v-if="chartData(widget.type).length" :data="chartData(widget.type)" :center-label="chartCenter(widget.type)" />
          <div v-else class="widget-empty">No data available</div>
        </template>
      </article>
      <button v-if="editing" class="add-widget" @click="showWidgetPicker = true">+ Add widget</button>
    </div>

    <Teleport to="body"><div v-if="showWidgetPicker" class="modal-backdrop" @click.self="showWidgetPicker = false"><div class="modal dash-modal"><div class="modal-header"><span class="modal-title">Add widget</span><button class="btn-icon" @click="showWidgetPicker = false">×</button></div><div class="modal-body widget-picker"><button v-for="type in availableWidgets" :key="type" @click="addWidget(type)"><strong>{{ widgetLabels[type] }}</strong><span>{{ widgetDescriptions[type] }}</span></button></div></div></div></Teleport>
    <Teleport to="body"><div v-if="showSettings" class="modal-backdrop" @click.self="showSettings = false"><div class="modal dash-modal"><div class="modal-header"><span class="modal-title">Manage dashboard</span><button class="btn-icon" @click="showSettings = false">×</button></div><div class="modal-body"><label class="field-label">Name<input v-model="settingsName" class="form-input" /></label><label class="field-label">Sites <select v-model="settingsSiteIds" multiple class="form-input site-select"><option v-for="company in companies" :key="company.id" :value="company.id">{{ company.name }}</option></select><span class="field-hint">No selections means all sites.</span></label><label class="home-check"><input v-model="settingsHome" type="checkbox" /> Make this the home dashboard</label></div><div class="modal-footer"><button class="btn btn-danger btn-sm" :disabled="dashboards.length <= 1" @click="deleteDashboard">Delete</button><span class="modal-spacer"/><button class="btn btn-ghost btn-sm" @click="createDashboard('blank')">New blank</button><button class="btn btn-ghost btn-sm" @click="createDashboard('default')">New default</button><button class="btn btn-ghost btn-sm" @click="cloneDashboard">Clone</button><button class="btn btn-primary btn-sm" @click="saveSettings">Save</button></div></div></div></Teleport>
  </div>
</template>

<script setup lang="ts">
import { computed, onMounted, onUnmounted, ref, watch } from 'vue';
import { useRoute, useRouter } from 'vue-router';
import { api, type AlertState, type DashboardData, type DashboardDetail, type DashboardWidget, type DashboardWidgetType, type Tenant } from '../api';
import { hasRole } from '../auth';
import DonutChart from '../components/DonutChart.vue';

const route = useRoute(), router = useRouter();
const dashboard = ref<DashboardDetail | null>(null), dashboards = ref<DashboardDetail[]>([]), data = ref<DashboardData | null>(null), companies = ref<Tenant[]>([]), error = ref('');
const editing = ref(false), draggingId = ref<string | null>(null), showWidgetPicker = ref(false), showSettings = ref(false);
const settingsName = ref(''), settingsSiteIds = ref<string[]>([]), settingsHome = ref(false);
const companyId = computed(() => typeof route.query.company === 'string' ? route.query.company : undefined);
const widgetLabels: Record<DashboardWidgetType, string> = { device_summary: 'Device summary', online_offline: 'Online / Offline', os_distribution: 'Operating systems', class_distribution: 'Device classes', antivirus_status: 'Antivirus status', offline_by_type: 'Offline devices by type', alerts_by_priority: 'Alerts by priority', recent_alerts: 'Recent alerts' };
const widgetDescriptions: Record<DashboardWidgetType, string> = { device_summary: 'Key device and alert counts', online_offline: 'Approved device availability', os_distribution: 'Device distribution by OS', class_distribution: 'Device distribution by class', antivirus_status: 'Current antivirus reporting state', offline_by_type: 'Alerting offline devices by class', alerts_by_priority: 'Open alerts by priority', recent_alerts: 'Latest alert activity' };
const availableWidgets = Object.keys(widgetLabels) as DashboardWidgetType[];
const activeAlerts = computed(() => (data.value?.alerts ?? []).filter(alert => alert.is_alerting === 1));
const recentAlerts = computed(() => [...(data.value?.alerts ?? [])].slice(0, 12));
const priorityOrder = ['critical', 'high', 'moderate', 'low'];
const alertBreakdown = computed(() => { const counts: Record<string, number> = {}; for (const alert of activeAlerts.value) counts[alert.priority] = (counts[alert.priority] ?? 0) + 1; return priorityOrder.filter(key => counts[key]).map(key => `${counts[key]} ${key}`).join(', ') || 'no issues detected'; });
const colors = { primary: 'var(--color-primary)', success: 'var(--color-success)', warning: 'var(--color-warning)', danger: 'var(--color-danger)', muted: 'var(--color-text-muted)', border: 'var(--color-border-strong)' };
function chartData(type: DashboardWidgetType) { const summary = data.value?.summary; if (!summary) return []; if (type === 'online_offline') return [{ label: 'Online', value: summary.online, color: colors.success }, { label: 'Offline', value: summary.offline, color: colors.border }]; const map = type === 'os_distribution' ? summary.by_os : type === 'class_distribution' ? summary.by_class : type === 'antivirus_status' ? summary.by_av_status : type === 'offline_by_type' ? summary.offline_by_class : null; if (type === 'alerts_by_priority') { const count: Record<string, number> = {}; for (const alert of activeAlerts.value) count[alert.priority] = (count[alert.priority] ?? 0) + 1; return priorityOrder.filter(key => count[key]).map(key => ({ label: key, value: count[key], color: key === 'critical' ? colors.danger : key === 'high' ? '#e07830' : key === 'moderate' ? colors.warning : colors.muted })); } return Object.entries(map ?? {}).map(([label, value], index) => ({ label, value, color: [colors.primary, colors.success, colors.warning, colors.danger, colors.muted][index % 5] })); }
function chartCenter(type: DashboardWidgetType) { return type === 'online_offline' ? 'approved' : type === 'alerts_by_priority' ? 'alerts' : type === 'offline_by_type' ? 'offline' : 'devices'; }
function widgetStyle(widget: DashboardWidget) { return { gridColumn: `${widget.x + 1} / span ${widget.w}`, gridRow: `${widget.y + 1} / span ${widget.h}` }; }
function startDrag(id: string) { draggingId.value = id; }
async function dropOnWidget(target: DashboardWidget) { if (!editing.value || !draggingId.value || draggingId.value === target.id || !dashboard.value) return; const source = dashboard.value.widgets.find(widget => widget.id === draggingId.value); if (!source) return; const sourceLayout = { x: source.x, y: source.y, w: source.w, h: source.h }; source.x = target.x; source.y = target.y; target.x = sourceLayout.x; target.y = sourceLayout.y; await Promise.all([api.dashboards.widgets.update(dashboard.value.id, source.id, { layout: source }), api.dashboards.widgets.update(dashboard.value.id, target.id, { layout: target })]).catch(load); }
function dropOnCanvas() { draggingId.value = null; }
async function resize(widget: DashboardWidget, change: number) { if (!dashboard.value) return; const w = Math.max(2, Math.min(12 - widget.x, widget.w + change)); if (w === widget.w) return; widget.w = w; await api.dashboards.widgets.update(dashboard.value.id, widget.id, { layout: widget }).catch(load); }
async function addWidget(type: DashboardWidgetType) { if (!dashboard.value) return; showWidgetPicker.value = false; try { await api.dashboards.widgets.create(dashboard.value.id, { type }); await load(); } catch (e: any) { error.value = e.message; } }
async function removeWidget(widgetId: string) { if (!dashboard.value || !confirm('Remove this widget?')) return; await api.dashboards.widgets.delete(dashboard.value.id, widgetId); await load(); }
function openSettings() { if (!dashboard.value) return; settingsName.value = dashboard.value.name; settingsSiteIds.value = [...dashboard.value.siteIds]; settingsHome.value = dashboard.value.isHome; showSettings.value = true; }
watch(showSettings, shown => { if (shown) openSettings(); });
async function saveSettings() { if (!dashboard.value) return; const updated = await api.dashboards.update(dashboard.value.id, { name: settingsName.value, siteIds: settingsSiteIds.value, isHome: settingsHome.value }); dashboard.value = updated; showSettings.value = false; await loadList(); window.dispatchEvent(new Event('beacon:dashboards-changed')); }
async function cloneDashboard() { if (!dashboard.value) return; const clone = await api.dashboards.clone(dashboard.value.id); showSettings.value = false; window.dispatchEvent(new Event('beacon:dashboards-changed')); await router.push(`/dashboards/${clone.id}`); }
async function createDashboard(template: 'default' | 'blank') { const name = prompt(`Name this ${template === 'default' ? 'Default' : 'Blank'} dashboard`, template === 'default' ? 'New Dashboard' : 'Blank Dashboard'); if (!name?.trim()) return; const created = await api.dashboards.create({ name: name.trim(), template }); showSettings.value = false; window.dispatchEvent(new Event('beacon:dashboards-changed')); await router.push(`/dashboards/${created.id}`); }
async function deleteDashboard() { if (!dashboard.value || dashboards.value.length <= 1 || !confirm(`Delete ${dashboard.value.name}?`)) return; await api.dashboards.delete(dashboard.value.id); const next = dashboards.value.find(item => item.id !== dashboard.value?.id); showSettings.value = false; window.dispatchEvent(new Event('beacon:dashboards-changed')); if (next) await router.push(`/dashboards/${next.id}`); }
async function loadList() { dashboards.value = await api.dashboards.list() as DashboardDetail[]; }
async function load() { const id = route.params.id as string; if (!id) return; try { const [detail, snapshot] = await Promise.all([api.dashboards.get(id), api.dashboards.data(id, companyId.value)]); dashboard.value = detail; data.value = snapshot; error.value = ''; } catch (e: any) { error.value = e.message; } }
function formatDate(ts: number | null) { return ts ? new Date(ts * 1000).toLocaleString() : '—'; }
function categoryLabel(type: string) { return ({ disk_space: 'Disk Space', offline: 'Online Status', cpu_usage: 'CPU', memory_usage: 'Memory', av_status: 'Antivirus', file_size: 'File/Folder Size', ping: 'Ping', process: 'Process', service: 'Service', software: 'Software' } as Record<string, string>)[type] ?? type; }
function alertMessage(alert: AlertState) { try { const config = JSON.parse(alert.config) as Record<string, unknown>; if (alert.check_type === 'offline') return (config.direction ?? 'offline') === 'online' ? 'Device came online' : 'Device went offline'; if (alert.check_type === 'cpu_usage') return `CPU usage above ${config.percent_max}%`; if (alert.check_type === 'memory_usage') return `Memory usage above ${config.percent_max}%`; if (alert.check_type === 'ping') return `${config.target} failing ping conditions`; return alert.policy_name; } catch { return alert.check_type; } }
let timer: ReturnType<typeof setInterval>;
onMounted(async () => { await Promise.all([loadList(), api.tenants.list().then(value => companies.value = value)]); await load(); timer = setInterval(load, 30_000); }); onUnmounted(() => clearInterval(timer)); watch(() => [route.params.id, companyId.value], load);
</script>

<style scoped>
.dash-head { display:flex; justify-content:space-between; align-items:flex-start; margin-bottom:20px; gap:16px; } h1 { margin:0; font-size:20px; }.dash-context { margin:5px 0 0; color:var(--color-text-muted); font-size:12px; }.dash-actions { display:flex; gap:8px; }.dash-loading,.widget-empty { color:var(--color-text-muted); font-size:13px; padding:32px; text-align:center; }.dash-grid { display:grid; grid-template-columns:repeat(12,minmax(0,1fr)); grid-auto-rows:8px; column-gap:14px; row-gap:14px; }.dash-widget { min-width:0; min-height:0; overflow:hidden; display:flex; flex-direction:column; background:var(--color-surface); border:1px solid var(--color-border); border-radius:8px; padding:14px; }.dash-grid.editing .dash-widget { border-style:dashed; cursor:grab; }.dash-widget.dragging { opacity:.45; }.widget-editbar { display:flex; justify-content:space-between; align-items:center; margin:-6px -6px 8px; color:var(--color-text-muted); font-size:10px; }.drag-handle { letter-spacing:1px; }.widget-edit-actions { display:flex; gap:3px; }.widget-edit-actions button { background:var(--color-surface-raised); border:1px solid var(--color-border); color:var(--color-text-muted); border-radius:3px; width:20px; height:20px; cursor:pointer; }.add-widget { grid-column:1 / span 3; min-height:110px; color:var(--color-primary); border:1px dashed var(--color-primary); border-radius:8px; background:transparent; cursor:pointer; font-size:13px; }.dash-stats { height:100%; flex:1; grid-template-columns:repeat(4,minmax(0,1fr)); gap:10px; }.dash-stats .stat-card { min-width:0; padding:12px; }.widget-title { display:flex; justify-content:space-between; align-items:center; font-size:13px; font-weight:700; margin-bottom:8px; }.widget-title a { font-size:11px; font-weight:400; }.widget-chart :deep(.donut-wrap) { flex:1; min-height:0; align-items:center; }.widget-chart :deep(.donut-legend) { gap:6px; }.widget-table-wrap { min-height:0; flex:1; overflow:auto; }.widget-table { width:100%; border-collapse:collapse; font-size:12px; }.widget-table th { text-align:left; color:var(--color-text-muted); font-size:10px; text-transform:uppercase; padding:7px 9px; border-bottom:1px solid var(--color-border); }.widget-table td { padding:8px 9px; border-bottom:1px solid var(--color-border); white-space:nowrap; }.widget-table tr { cursor:pointer; }.widget-table tr:hover td { background:var(--color-surface-raised); }.empty-cell { color:var(--color-text-muted); text-align:center; }.pri-badge { display:inline-block; padding:2px 7px; border-radius:10px; font-size:10px; font-weight:700; text-transform:capitalize; }.pri-critical { background:var(--color-danger); color:#fff; }.pri-high { background:#e07830; color:#fff; }.pri-moderate { background:var(--color-warning); color:#1a1200; }.pri-low { background:var(--color-text-muted); color:var(--color-surface); }.dash-modal { width:min(560px,calc(100vw - 32px)); }.widget-picker { display:grid; grid-template-columns:repeat(2,1fr); gap:8px; }.widget-picker button { text-align:left; padding:12px; border:1px solid var(--color-border); background:var(--color-surface-raised); color:var(--color-text-primary); border-radius:6px; cursor:pointer; }.widget-picker button:hover { border-color:var(--color-primary); }.widget-picker span { display:block; margin-top:4px; color:var(--color-text-muted); font-size:11px; }.field-label { display:block; font-size:12px; color:var(--color-text-muted); margin-bottom:16px; }.form-input { display:block; width:100%; box-sizing:border-box; margin-top:6px; }.site-select { min-height:120px; }.field-hint { display:block; margin-top:5px; font-size:11px; }.home-check { font-size:12px; }.modal-footer { display:flex; align-items:center; }.modal-spacer { flex:1; }
@media (max-width:760px) { .dash-grid { display:block; }.dash-widget { min-height:220px; margin-bottom:14px; }.dash-widget:has(.dash-stats) { min-height:auto; }.dash-stats { grid-template-columns:repeat(2,1fr); }.add-widget { width:100%; min-height:80px; }.widget-picker { grid-template-columns:1fr; }.widget-table th:nth-child(4),.widget-table td:nth-child(4),.widget-table th:nth-child(5),.widget-table td:nth-child(5) { display:none; } }
</style>
